examples.code:
SELECT *
FROM orders
LIMIT 5;

SELECT *
FROM orders
LIMIT 10 OFFSET 10;

cards.syntax:
SELECT *
FROM table_name
WHERE column = value;

examples.code:
SELECT *
FROM orders
WHERE amount > 1000;

SELECT *
FROM users
WHERE country <> 'Russia';

cards.syntax:
SELECT *
FROM table_name
WHERE condition1 AND condition2;

SELECT *
FROM table_name
WHERE condition1 OR condition2;

examples.code:
SELECT *
FROM users
WHERE city = 'Москва' AND is_active = true;

SELECT *
FROM orders
WHERE discount > 0 OR customer_type = 'VIP';

cards.syntax:
SELECT *
FROM table_name
WHERE column IN (value1, value2, ...);

examples.code:
SELECT *
FROM orders
WHERE status IN ('pending', 'shipped', 'delivered');

cards.syntax:
SELECT *
FROM table_name
WHERE column BETWEEN value1 AND value2;

examples.code:
SELECT *
FROM orders
WHERE created_at BETWEEN '2024-03-01' AND '2024-03-31';

SELECT *
FROM orders
WHERE amount BETWEEN 500 AND 2000;

cards.syntax:
SELECT *
FROM table_name
WHERE column LIKE 'pattern%';

examples.code:
SELECT *
FROM users
WHERE email LIKE '%@gmail.com';

SELECT *
FROM users
WHERE name ILIKE 'а%';

cards.syntax:
SELECT *
FROM table_name
WHERE column IS NULL;

SELECT *
FROM table_name
WHERE column IS NOT NULL;

examples.code:
SELECT *
FROM users
WHERE city IS NULL;

cards.syntax:
SELECT *
FROM table_name
ORDER BY column1 ASC, column2 DESC;

examples.code:
SELECT *
FROM orders
ORDER BY created_at DESC, amount DESC;

SELECT *
FROM users
ORDER BY last_login DESC NULLS LAST;

cards.syntax:
SELECT t1.col, t2.col
FROM table1 t1
CROSS JOIN table2 t2;

SELECT *
FROM table_name
WHERE column IN (
    SELECT column FROM other_table
);

examples.code:
SELECT *
FROM users
WHERE id IN (
    SELECT DISTINCT user_id FROM orders
);

SELECT *
FROM orders
WHERE amount > (
    SELECT AVG(amount) FROM orders
);

cards.syntax:
SELECT t.col
FROM (
    SELECT ... FROM ...
) t;

WITH cte_name AS (
    SELECT ...
)
SELECT * FROM cte_name;

SELECT col FROM table1
UNION ALL
SELECT col FROM table2;

examples.code:
SELECT user_id, 'purchase' AS action, created_at FROM orders
UNION ALL
SELECT user_id, 'signup' AS action, created_at FROM users;

cards.syntax:
SELECT col FROM table1
INTERSECT
SELECT col FROM table2;

examples.code:
SELECT user_id FROM orders WHERE created_at >= '2024-01-01' AND created_at < '2024-02-01'
INTERSECT
SELECT user_id FROM orders WHERE created_at >= '2024-02-01' AND created_at < '2024-03-01';

cards.syntax:
SELECT col FROM table1
EXCEPT
SELECT col FROM table2;

examples.code:
SELECT id FROM users
EXCEPT
SELECT user_id FROM orders;

cards.syntax:
function() OVER (
    PARTITION BY column1
    ORDER BY column2
)

examples.code:
SELECT *
FROM orders
WHERE created_at >= CURRENT_DATE - INTERVAL '7 days';

SELECT DISTINCT user_id
FROM activity
WHERE event_time >= CURRENT_TIMESTAMP - INTERVAL '30 days';

SELECT 
    TO_DATE('15.03.2024', 'DD.MM.YYYY') AS d1,
    '2024-03-15'::date AS d2;

SELECT 
    CONCAT(first_name, ' ', last_name) AS full_name
FROM users;

SELECT 
    CONCAT_WS(', ', city, country) AS location
FROM users;
